/**
 * PrismLite — minimal JSON + JavaScript syntax highlighter.
 * No dependencies. Designed for Claude Code Visual Guide.
 */

(function (global) {
  'use strict';

  /* ------------------------------------------------------------------
     JSON Highlighter
  ------------------------------------------------------------------ */

  /**
   * Highlight a JSON string, returning HTML with <span> colour classes.
   * Input should already be HTML-escaped (or pass raw=true for auto-escape).
   * @param {string} json
   * @param {boolean} [raw=false] - if true, escapes the string first
   * @returns {string} HTML string
   */
  function highlightJSON(json, raw) {
    if (raw) json = _escapeHtml(json);

    return json.replace(
      /("(?:\\u[a-fA-F0-9]{4}|\\[^u]|[^\\"])*"(\s*:)?|\b(true|false|null)\b|-?\d+(?:\.\d*)?(?:[eE][+\-]?\d+)?)/g,
      function (match) {
        let cls = 'json-number';
        if (/^"/.test(match)) {
          cls = /:$/.test(match) ? 'json-key' : 'json-string';
        } else if (/^(true|false)$/.test(match)) {
          cls = 'json-boolean';
        } else if (match === 'null') {
          cls = 'json-null';
        }
        return '<span class="' + cls + '">' + match + '</span>';
      }
    );
  }

  /* ------------------------------------------------------------------
     JavaScript / Generic Highlighter
  ------------------------------------------------------------------ */

  /**
   * Very lightweight JavaScript tokeniser.
   * Covers: strings, template literals, comments, keywords, numbers,
   * booleans/null/undefined, function names, operators.
   * @param {string} code - raw JS source (will be HTML-escaped internally)
   * @returns {string} HTML string
   */
  function highlightJS(code) {
    // We process token by token to avoid nested-replace issues.
    const tokens = [];
    let i = 0;
    const src = code;

    while (i < src.length) {
      let m;

      // Single-line comment
      if (src[i] === '/' && src[i + 1] === '/') {
        const end = src.indexOf('\n', i);
        const text = end === -1 ? src.slice(i) : src.slice(i, end);
        tokens.push({ type: 'comment', raw: text });
        i += text.length;
        continue;
      }

      // Multi-line comment
      if (src[i] === '/' && src[i + 1] === '*') {
        const end = src.indexOf('*/', i + 2);
        const text = end === -1 ? src.slice(i) : src.slice(i, end + 2);
        tokens.push({ type: 'comment', raw: text });
        i += text.length;
        continue;
      }

      // Template literal
      if (src[i] === '`') {
        let j = i + 1;
        while (j < src.length) {
          if (src[j] === '\\') { j += 2; continue; }
          if (src[j] === '`') { j++; break; }
          j++;
        }
        tokens.push({ type: 'string', raw: src.slice(i, j) });
        i = j;
        continue;
      }

      // String (single or double quote)
      if (src[i] === '"' || src[i] === "'") {
        const q = src[i];
        let j = i + 1;
        while (j < src.length) {
          if (src[j] === '\\') { j += 2; continue; }
          if (src[j] === q) { j++; break; }
          j++;
        }
        tokens.push({ type: 'string', raw: src.slice(i, j) });
        i = j;
        continue;
      }

      // Number
      m = src.slice(i).match(/^-?(?:0x[\da-fA-F]+|0b[01]+|0o[0-7]+|\d+(?:\.\d*)?(?:[eE][+\-]?\d+)?)/);
      if (m && (i === 0 || /[\s(,=+\-*/%&|^~!<>?:[\]{};]/.test(src[i - 1]))) {
        tokens.push({ type: 'number', raw: m[0] });
        i += m[0].length;
        continue;
      }

      // Keyword / identifier
      m = src.slice(i).match(/^[a-zA-Z_$][\w$]*/);
      if (m) {
        const word = m[0];
        const isKw = _JS_KEYWORDS.has(word);
        const isBool = word === 'true' || word === 'false';
        const isNull = word === 'null' || word === 'undefined' || word === 'NaN' || word === 'Infinity';
        // Check if next non-space is '(' → function call
        const rest = src.slice(i + word.length).trimStart();
        const isFn = rest[0] === '(';

        let type = 'identifier';
        if (isKw) type = 'keyword';
        else if (isBool) type = 'boolean';
        else if (isNull) type = 'null';
        else if (isFn) type = 'function';

        tokens.push({ type, raw: word });
        i += word.length;
        continue;
      }

      // Operator / punctuation (collect runs)
      m = src.slice(i).match(/^[+\-*/%=&|^~!<>?:;,.[\]{}()]+/);
      if (m) {
        tokens.push({ type: 'punctuation', raw: m[0] });
        i += m[0].length;
        continue;
      }

      // Whitespace / newlines (preserve verbatim)
      m = src.slice(i).match(/^[\s\S]/);
      if (m) {
        tokens.push({ type: 'plain', raw: m[0] });
        i += m[0].length;
      }
    }

    // Render
    return tokens.map(tok => {
      const esc = _escapeHtml(tok.raw);
      switch (tok.type) {
        case 'comment':     return `<span class="token comment">${esc}</span>`;
        case 'string':      return `<span class="token string">${esc}</span>`;
        case 'number':      return `<span class="token number">${esc}</span>`;
        case 'keyword':     return `<span class="token keyword">${esc}</span>`;
        case 'boolean':     return `<span class="token boolean">${esc}</span>`;
        case 'null':        return `<span class="token constant">${esc}</span>`;
        case 'function':    return `<span class="token function">${esc}</span>`;
        case 'punctuation': return `<span class="token punctuation">${esc}</span>`;
        default:            return esc;
      }
    }).join('');
  }

  /* ------------------------------------------------------------------
     Auto-highlight: process <pre><code> blocks in DOM
  ------------------------------------------------------------------ */

  /**
   * Scan the document for <code> elements and apply highlighting.
   * Respects class="language-json" / "language-javascript" / "language-js".
   */
  function highlightAll() {
    document.querySelectorAll('code[class*="language-"]').forEach(function (el) {
      const cls = el.className;
      const raw = el.textContent;

      if (cls.includes('language-json')) {
        el.innerHTML = highlightJSON(_escapeHtml(raw));
      } else if (cls.includes('language-javascript') || cls.includes('language-js')) {
        el.innerHTML = highlightJS(raw);
      }
    });
  }

  /* ------------------------------------------------------------------
     Utilities
  ------------------------------------------------------------------ */

  function _escapeHtml(str) {
    return String(str)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  /** JS reserved words + common globals */
  const _JS_KEYWORDS = new Set([
    'async', 'await', 'break', 'case', 'catch', 'class', 'const', 'continue',
    'debugger', 'default', 'delete', 'do', 'else', 'export', 'extends',
    'finally', 'for', 'from', 'function', 'get', 'if', 'import', 'in',
    'instanceof', 'let', 'new', 'of', 'return', 'set', 'static', 'super',
    'switch', 'this', 'throw', 'try', 'typeof', 'var', 'void', 'while',
    'with', 'yield',
  ]);

  /* ------------------------------------------------------------------
     Auto-run on DOMContentLoaded
  ------------------------------------------------------------------ */

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', highlightAll);
  } else {
    highlightAll();
  }

  /* ------------------------------------------------------------------
     Export
  ------------------------------------------------------------------ */

  global.PrismLite = {
    highlightJSON: highlightJSON,
    highlightJS: highlightJS,
    highlightAll: highlightAll,
  };

})(typeof window !== 'undefined' ? window : this);
